// We securely lock this family tree indefinitely
sealed class NetworkResult {
    object Loading : NetworkResult()
    // Success natively carries the specific payload data!
    data class Success(val data: String) : NetworkResult()
    // Error natively carries the specific failure cause!
    data class Error(val message: String) : NetworkResult()
}

fun handleResult(result: NetworkResult) {
    when (result) {
        is NetworkResult.Loading -> println("Spinning...")
        // The compiler structurally extracts data purely safely magically
        is NetworkResult.Success -> println("Downloaded: ${result.data}")
        is NetworkResult.Error -> println("Crashed: ${result.message}")
    }
}
